-- Teaching schema — loaded at startup by DbConnection.initSchema()
--
-- H2 in-memory syntax used here is wire-compatible with MySQL:
--   AUTO_INCREMENT  — H2 treats this as an alias for GENERATED BY DEFAULT AS IDENTITY
--   VARCHAR, INTEGER — standard SQL types accepted by both engines
--
-- To point the same DAO code at a real MySQL instance, change only:
--   1. DbConnection.URL  (e.g. jdbc:mysql://localhost:3306/teaching)
--   2. DbConnection.USER / PASSWORD
-- No DAO or SQL changes needed.

CREATE TABLE IF NOT EXISTS students (
    id    INTEGER      PRIMARY KEY AUTO_INCREMENT,
    name  VARCHAR(100) NOT NULL,
    age   INTEGER      NOT NULL,
    grade VARCHAR(2)   NOT NULL
);
